import React from 'react';
import { useUser } from '../hooks/useUser';
import CaseCard from '../components/CaseCard';

// Временные мок-данные (позже заменим на запрос к API)
const mockCases = [
  { id: 1, name: 'Базовый кейс', price_stars: 50, image_url: 'https://via.placeholder.com/150' },
  { id: 2, name: 'Премиум кейс', price_stars: 200, image_url: 'https://via.placeholder.com/150' },
];

const Home: React.FC = () => {
  const { user } = useUser();

  const handleOpenCase = (caseId: number) => {
    // Позже здесь будет переход на страницу открытия или модалка
    console.log('Open case', caseId);
  };

  return (
    <div>
      <h1>Добро пожаловать, {user?.first_name || 'игрок'}!</h1>
      <div style={{ display: 'flex', gap: '20px', flexWrap: 'wrap' }}>
        {mockCases.map(caseItem => (
          <CaseCard
            key={caseItem.id}
            caseData={caseItem}
            onOpen={() => handleOpenCase(caseItem.id)}
          />
        ))}
      </div>
    </div>
  );
};

export default Home;
